"""
instalar_tudo.py - Reescreve app.py, conciliador.py e exportar.py de uma vez.
Execute: python instalar_tudo.py
"""
import os

BASE = os.path.dirname(os.path.abspath(__file__))

def salvar(nome, conteudo):
    path = os.path.join(BASE, nome)
    with open(path, "w", encoding="utf-8") as f:
        f.write(conteudo)
    print(f"OK: {nome} reescrito ({len(conteudo)} chars)")

APP = 'import streamlit as st\nimport pandas as pd\nimport numpy as np\n\nfrom conciliador import detect_columns, load_sheet, conciliar, resumo\nfrom exportar import exportar_excel, exportar_csv_erp\nfrom exportar_pdf import exportar_pdf\n\nst.set_page_config(\n    page_title="Conciliador Bancário",\n    page_icon="⇄",\n    layout="wide",\n    initial_sidebar_state="collapsed",\n)\n\nst.markdown("""\n<style>\nhtml, body, [class*="css"] { font-family: \'Segoe UI\', Arial, sans-serif; }\n.stApp { background: #f8f9fb; }\n.concil-header {\n    background: linear-gradient(135deg, #085041 0%, #0F6E56 100%);\n    color: white; padding: 1.5rem 2rem; border-radius: 12px; margin-bottom: 1.5rem;\n    display: flex; align-items: center; gap: 1rem;\n}\n.concil-header h1 { margin: 0; font-size: 1.6rem; font-weight: 600; }\n.concil-header p  { margin: 0; opacity: 0.85; font-size: 0.9rem; }\n.steps-bar {\n    display: flex; background: white; border-radius: 10px;\n    overflow: hidden; box-shadow: 0 1px 4px rgba(0,0,0,.08); margin-bottom: 1.5rem;\n}\n.step-item { flex:1; padding:.75rem 1rem; text-align:center; font-size:.82rem; color:#888; border-right:1px solid #eee; }\n.step-item:last-child { border-right:none; }\n.step-item.active { background:#E1F5EE; color:#085041; font-weight:600; }\n.step-item.done { color:#0F6E56; }\n.step-num { font-size:.7rem; display:block; color:#bbb; margin-bottom:2px; }\n.step-item.active .step-num, .step-item.done .step-num { color:#1D9E75; }\n.metric-card { background:white; border-radius:10px; padding:1.2rem 1.5rem; text-align:center; box-shadow:0 1px 4px rgba(0,0,0,.06); }\n.metric-val { font-size:2rem; font-weight:700; line-height:1; }\n.metric-lbl { font-size:.78rem; color:#888; margin-top:4px; }\n.metric-ok .metric-val { color:#0F6E56; }\n.metric-warn .metric-val { color:#BA7517; }\n.metric-err .metric-val { color:#A32D2D; }\n.metric-info .metric-val { color:#185FA5; }\n.badge { display:inline-block; padding:2px 10px; border-radius:20px; font-size:.78rem; font-weight:500; }\n.badge-ok   { background:#E1F5EE; color:#085041; }\n.badge-warn { background:#FAEEDA; color:#633806; }\n.badge-err  { background:#FCEBEB; color:#791F1F; }\n.badge-info { background:#E6F1FB; color:#0C447C; }\n.result-table { width:100%; border-collapse:collapse; font-size:.85rem; }\n.result-table th { background:#085041; color:white; padding:8px 10px; text-align:left; font-weight:500; position:sticky; top:0; }\n.result-table td { padding:7px 10px; border-bottom:1px solid #f0f0f0; white-space:nowrap; max-width:180px; overflow:hidden; text-overflow:ellipsis; }\n.result-table tr:hover td { background:#f5fbf8; }\n.section-title { font-size:.9rem; font-weight:600; color:#333; margin-bottom:.5rem; display:flex; align-items:center; gap:6px; }\n.progress-outer { background:#e8e8e8; border-radius:6px; height:10px; margin:6px 0 12px; overflow:hidden; }\n.progress-inner { height:100%; background:linear-gradient(90deg,#0F6E56,#1D9E75); border-radius:6px; transition:width .6s ease; }\ndiv[data-testid="stButton"] > button { border-radius:8px; font-weight:500; border:none; padding:.5rem 1.25rem; }\n.info-banner { background:#E6F1FB; border-left:4px solid #378ADD; border-radius:0 8px 8px 0; padding:.75rem 1rem; font-size:.85rem; color:#185FA5; margin-bottom:1rem; }\n</style>\n""", unsafe_allow_html=True)\n\n# ── Sessão ────────────────────────────────────────────────────────────────────\ndef _init():\n    for k, v in {"step":0,"raw_banco":None,"raw_erp":None,"map_banco":{},\n                 "map_erp":{},"df_result":None,"resumo":None,\n                 "resultado_completo":None}.items():\n        if k not in st.session_state:\n            st.session_state[k] = v\n_init()\nS = st.session_state\n\nSTEPS = ["Importar","Mapear colunas","Critérios","Resultado","Exportar"]\n\ndef render_steps():\n    html = \'<div class="steps-bar">\'\n    for i, label in enumerate(STEPS):\n        css = "active" if i==S.step else ("done" if i<S.step else "")\n        icon = "✓ " if i < S.step else ""\n        html += f\'<div class="step-item {css}"><span class="step-num">Etapa {i+1}</span>{icon}{label}</div>\'\n    html += "</div>"\n    st.markdown(html, unsafe_allow_html=True)\n\n# ── Palavras que indicam linha de cabeçalho real ──────────────────────────────\nPALAVRAS_CAB = [\n    "data","valor","debito","débito","credito","crédito","documento","doc",\n    "descricao","descrição","historico","histórico","lancamento","lançamento",\n    "fornecedor","cliente","razao","razão","social","cnpj","cpf","nf","nota",\n    "numero","número","ref","tipo","natureza","saldo","conta","agencia",\n    "agência","vencimento","pagamento","competencia","competência","dcto","nsu",\n]\n\ndef _score_cabecalho(linha) -> int:\n    score = 0\n    preenchidos = 0\n    for v in linha:\n        s = str(v).strip().lower() if v is not None else ""\n        if not s or s in ("nan","none"): continue\n        preenchidos += 1\n        if any(p in s for p in PALAVRAS_CAB): score += 3\n        if len(s) > 40: score -= 3          # frases longas = não é cabeçalho\n        s2 = s.replace(".","").replace(",","").replace("/","").replace("-","")\n        if s2.isdigit(): score -= 2         # número = não é cabeçalho\n    return score + min(preenchidos, 8)\n\ndef _ler_planilha(file, ext: str) -> pd.DataFrame:\n    """Lê qualquer planilha detectando automaticamente a linha do cabeçalho real."""\n    import io\n\n    # Para Excel: lê todas as abas e usa a que tem mais dados\n    if ext in ("xlsx", "xls", "xlsm"):\n        conteudo = file.read() if hasattr(file, "read") else open(file, "rb").read()\n        # XLS antigo usa xlrd, XLSX usa openpyxl\n        engine = "xlrd" if ext == "xls" else "openpyxl"\n        try:\n            xf = pd.ExcelFile(io.BytesIO(conteudo), engine=engine)\n        except Exception:\n            # fallback\n            engine = "xlrd" if engine == "openpyxl" else "openpyxl"\n            xf = pd.ExcelFile(io.BytesIO(conteudo), engine=engine)\n        melhor_aba, melhor_linhas = xf.sheet_names[0], 0\n        for aba in xf.sheet_names:\n            try:\n                df_teste = pd.read_excel(io.BytesIO(conteudo), sheet_name=aba,\n                                         dtype=str, header=None, nrows=5, engine=engine)\n                n = df_teste.notna().sum().sum()\n                if n > melhor_linhas:\n                    melhor_linhas, melhor_aba = n, aba\n            except: pass\n        bruto = pd.read_excel(io.BytesIO(conteudo), sheet_name=melhor_aba,\n                              dtype=str, header=None, engine=engine)\n    elif ext == "csv":\n        bruto = pd.read_csv(file, dtype=str, encoding="utf-8-sig",\n                            sep=None, engine="python", header=None)\n    else:\n        conteudo = file.read() if hasattr(file, "read") else open(file, "rb").read()\n        bruto = pd.read_excel(io.BytesIO(conteudo), dtype=str, header=None)\n\n    # Avalia as primeiras 15 linhas para achar o cabeçalho\n    melhor_idx, melhor_score = 0, -999\n    for i in range(min(15, len(bruto))):\n        sc = _score_cabecalho(bruto.iloc[i].tolist())\n        if sc > melhor_score:\n            melhor_score, melhor_idx = sc, i\n\n    # Reconstrói usando a linha encontrada como cabeçalho\n    cols = []\n    vistos = {}\n    for i, v in enumerate(bruto.iloc[melhor_idx].tolist()):\n        s = str(v).strip() if v is not None and str(v).strip() not in ("nan","None","") else ""\n        if not s:\n            s = f"_vazia_{i}"   # coluna sem nome → será removida a seguir\n        if s in vistos:\n            vistos[s] += 1\n            s = f"{s}_{vistos[s]}"\n        else:\n            vistos[s] = 0\n        cols.append(s)\n\n    df = bruto.iloc[melhor_idx + 1:].copy()\n    df.columns = cols\n    df = df.reset_index(drop=True)\n\n    # Remove colunas sem nome (vazias no cabeçalho) e colunas 100% vazias\n    df = df.loc[:, ~df.columns.str.startswith("_vazia_")]\n    df = df.loc[:, df.notna().any(axis=0)]\n    return df\n\ndef header():\n    st.markdown("""\n    <div class="concil-header">\n        <div style="font-size:2rem">⇄</div>\n        <div>\n            <h1>Conciliador Bancário</h1>\n            <p>Conciliação automática entre Extrato Bancário e ERP — qualquer formato de planilha</p>\n        </div>\n    </div>""", unsafe_allow_html=True)\n\ndef _badge_dc(dc):\n    if not dc or str(dc).strip() == "": return "—"\n    dc = str(dc).strip()\n    cor = "#085041" if dc=="C" else "#A32D2D" if dc=="D" else "#BA7517"\n    bg  = "#E1F5EE" if dc=="C" else "#FCEBEB" if dc=="D" else "#FAEEDA"\n    return f\'<span style="background:{bg};color:{cor};padding:1px 7px;border-radius:10px;font-size:11px;font-weight:600">{dc}</span>\'\n\ndef badge_html(status):\n    MAP = {\n        "Conciliado":    ("ok",   "✅ Conciliado"),\n        "Divergente":    ("warn", "⚠️ Divergente"),\n        "Nao Conciliado":("err",  "❌ Não Conciliado"),\n        "So no Banco":   ("err",  "🏦 Só no Banco"),\n        "So no ERP":     ("info", "🗄️ Só no ERP"),\n    }\n    cls, label = MAP.get(str(status), ("ok", str(status)))\n    return f\'<span class="badge badge-{cls}">{label}</span>\'\n\ndef conf_html(conf):\n    mapa = {"Alta":"ok","Media":"warn","Média":"warn","Baixa":"err","Muito Baixa":"err"}\n    cls = mapa.get(str(conf),"ok")\n    label = {"Media":"Média"}.get(str(conf), str(conf))  # corrige grafia\n    if str(conf) in mapa:\n        return f\'<span class="badge badge-{cls}">{label}</span>\'\n    return f\'<span style="color:#bbb">{label}</span>\'\n\ndef fmt_valor(v):\n    try:\n        if v is None: return "—"\n        f = float(v)\n        if np.isnan(f) or np.isinf(f): return "—"\n        s = f"{abs(f):,.2f}".replace(",","X").replace(".",",").replace("X",".")\n        return f"R$ {\'-\' if f<0 else \'\'}{s}"\n    except: return "—"\n\ndef fmt_data(d):\n    try:\n        if d is None or pd.isna(d): return "—"\n        return pd.Timestamp(d).strftime("%d/%m/%Y")\n    except: return str(d) if d else "—"\n\n# ── Etapa 0 — Importar ────────────────────────────────────────────────────────\ndef etapa_importar():\n    st.markdown(\'<div class="info-banner">📌 Importe qualquer planilha. O sistema detecta automaticamente onde começa o cabeçalho real, ignorando linhas de título ou observação.</div>\', unsafe_allow_html=True)\n    col1, col2 = st.columns(2)\n\n    with col1:\n        st.markdown(\'<div class="section-title">🏦 Extrato Bancário</div>\', unsafe_allow_html=True)\n        f = st.file_uploader("Banco", type=["xlsx","xls","csv"], label_visibility="collapsed", key="up_banco")\n        if f:\n            try:\n                ext = f.name.rsplit(".",1)[-1].lower()\n                raw = _ler_planilha(f, ext)\n                S.raw_banco = raw\n                S.map_banco = detect_columns(raw)\n                st.success(f"✅ **{f.name}** — {len(raw)} linhas, {len(raw.columns)} colunas detectadas")\n                with st.expander("Pré-visualização (5 primeiras linhas)"):\n                    st.dataframe(raw.head(5), use_container_width=True)\n            except Exception as e:\n                st.error(f"Erro ao ler arquivo: {e}")\n\n    with col2:\n        st.markdown(\'<div class="section-title">🗄️ Financeiro / ERP</div>\', unsafe_allow_html=True)\n        f = st.file_uploader("ERP", type=["xlsx","xls","csv"], label_visibility="collapsed", key="up_erp")\n        if f:\n            try:\n                ext = f.name.rsplit(".",1)[-1].lower()\n                raw = _ler_planilha(f, ext)\n                S.raw_erp = raw\n                S.map_erp = detect_columns(raw)\n                st.success(f"✅ **{f.name}** — {len(raw)} linhas, {len(raw.columns)} colunas detectadas")\n                with st.expander("Pré-visualização (5 primeiras linhas)"):\n                    st.dataframe(raw.head(5), use_container_width=True)\n            except Exception as e:\n                st.error(f"Erro ao ler arquivo: {e}")\n\n    st.divider()\n    _, btn_col = st.columns([5,1])\n    with btn_col:\n        if st.button("Próximo →", type="primary", use_container_width=True):\n            if S.raw_banco is None or S.raw_erp is None:\n                st.warning("Importe os dois arquivos antes de continuar.")\n            else:\n                S.step = 1; st.rerun()\n\n# ── Etapa 1 — Mapear colunas ──────────────────────────────────────────────────\nCAMPOS = ["data","valor","debito","credito","descricao","documento","tipo"]\nCAMPOS_LABEL = {\n    "data":      "📅 Data",\n    "valor":     "💰 Valor (coluna única — ex: Itaú com negativos)",\n    "debito":    "➖ Débito (coluna separada)",\n    "credito":   "➕ Crédito (coluna separada)",\n    "descricao": "📝 Descrição / Histórico / Fornecedor",\n    "documento": "🔢 Nº Documento / NF",\n    "tipo":      "🔄 Tipo (D/C)",\n}\nCAMPOS_HELP = {\n    "valor":   "Use quando débito e crédito estão na mesma coluna. Ex: -100 (débito) e 200 (crédito).",\n    "debito":  "Use quando há uma coluna só para saídas/débitos.",\n    "credito": "Use quando há uma coluna só para entradas/créditos.",\n}\n\ndef etapa_mapear():\n    st.markdown(\'<div class="info-banner">🗺️ Confirme o mapeamento automático. Os nomes mostrados são exatamente os das colunas da sua planilha.</div>\', unsafe_allow_html=True)\n    col1, col2 = st.columns(2)\n\n    for side, label, raw_key, map_key in [\n        (col1, "🏦 Extrato Bancário", "raw_banco", "map_banco"),\n        (col2, "🗄️ ERP / Financeiro", "raw_erp",   "map_erp"),\n    ]:\n        raw = S[raw_key]\n        if raw is None: continue\n        # Filtra colunas com nomes claramente inválidos (frases longas, não são cabeçalhos)\n        cols_validas = [\n            col for col in raw.columns\n            if len(str(col)) <= 50 and not str(col).startswith("_vazia_")\n        ]\n        opcoes = ["(não usar)"] + cols_validas\n\n        with side:\n            st.markdown(f\'<div class="section-title">{label}</div>\', unsafe_allow_html=True)\n            for campo in CAMPOS:\n                atual = S[map_key].get(campo)\n                idx = opcoes.index(atual) if atual in opcoes else 0\n                escolha = st.selectbox(\n                    CAMPOS_LABEL[campo], opcoes, index=idx,\n                    key=f"sel_{map_key}_{campo}",\n                    help=CAMPOS_HELP.get(campo),\n                )\n                S[map_key][campo] = None if escolha == "(não usar)" else escolha\n                if campo == "valor":\n                    st.markdown("<div style=\'border-top:1px dashed #ddd;margin:6px 0;font-size:11px;color:#aaa;text-align:center\'>— ou colunas separadas —</div>", unsafe_allow_html=True)\n                if campo == "credito":\n                    st.markdown("<div style=\'border-top:1px dashed #ddd;margin:6px 0\'></div>", unsafe_allow_html=True)\n\n    st.divider()\n    b1, _, b2 = st.columns([1,4,1])\n    with b1:\n        if st.button("← Voltar", use_container_width=True): S.step=0; st.rerun()\n    with b2:\n        if st.button("Próximo →", type="primary", use_container_width=True): S.step=2; st.rerun()\n\n# ── Etapa 2 — Critérios ───────────────────────────────────────────────────────\ndef etapa_criterios():\n    st.markdown("### ⚙️ Configure os critérios de conciliação")\n    col1, col2 = st.columns(2)\n    with col1:\n        usar_valor = st.checkbox("Bater por **Valor**", value=True)\n        tol_valor  = st.number_input("Tolerância de valor (R$)", min_value=0.0, value=0.01, step=0.01, disabled=not usar_valor, format="%.2f")\n        usar_doc   = st.checkbox("Bater por **Nº Documento / NF**", value=True)\n    with col2:\n        usar_data  = st.checkbox("Bater por **Data**", value=True)\n        tol_dias   = st.number_input("Tolerância de data (dias)", min_value=0, value=2, step=1, disabled=not usar_data)\n        usar_desc  = st.checkbox("Bater por **Descrição** (fuzzy)", value=False)\n        min_sim    = st.slider("Similaridade mínima (%)", 50, 100, 70, disabled=not usar_desc)\n\n    st.info("💡 Prioridade automática: Valor + Data + Documento → Valor + Data → Valor apenas.")\n    st.divider()\n    b1, _, b2 = st.columns([1,4,1])\n    with b1:\n        if st.button("← Voltar", use_container_width=True): S.step=1; st.rerun()\n    with b2:\n        if st.button("▶ Executar Conciliação", type="primary", use_container_width=True):\n            with st.spinner("Conciliando lançamentos..."):\n                df_b = load_sheet(S.raw_banco, S.map_banco)\n                df_e = load_sheet(S.raw_erp,   S.map_erp)\n                result = conciliar(df_b, df_e,\n                    tol_valor=tol_valor if usar_valor else 0,\n                    tol_dias=tol_dias   if usar_data  else 0,\n                    usar_documento=usar_doc,\n                    usar_descricao=usar_desc,\n                    min_similaridade=min_sim/100,\n                )\n            if isinstance(result, dict):\n                S.resultado_completo = result\n                S.df_result = result["resultado"]\n                S.resumo    = result["resumo"]\n            else:\n                S.df_result = result\n                S.resumo    = resumo(result)\n                S.resultado_completo = {\n                    "resultado": result, "resumo": S.resumo,\n                    "agrupamentos":[], "sugestoes":[],\n                    "duplicidades_banco": pd.DataFrame(),\n                    "duplicidades_erp":   pd.DataFrame(),\n                }\n            S.step = 3; st.rerun()\n\n# ── Etapa 3 — Resultado ───────────────────────────────────────────────────────\ndef etapa_resultado():\n    r  = S.resumo\n    df = S.df_result\n\n    m1,m2,m3,m4,m5 = st.columns(5)\n    for col, val, lbl, css in [\n        (m1, r["total_banco"],  "Total Banco",     "metric-card"),\n        (m2, r["conciliados"],  "Conciliados",     "metric-card metric-ok"),\n        (m3, r["divergentes"],  "Divergentes",     "metric-card metric-warn"),\n        (m4, r.get("so_banco", r.get("nao_conciliados",0)), "Só no Banco", "metric-card metric-err"),\n        (m5, r["so_erp"],       "Só no ERP",       "metric-card metric-info"),\n    ]:\n        with col:\n            st.markdown(f\'<div class="{css}"><div class="metric-val">{val}</div><div class="metric-lbl">{lbl}</div></div>\', unsafe_allow_html=True)\n\n    pct = r["taxa_pct"]\n    st.markdown(f"""\n    <div style="margin-top:1rem">\n        <div style="display:flex;justify-content:space-between;font-size:.82rem;color:#666;margin-bottom:4px">\n            <span>Taxa de conciliação</span><span><b>{pct}%</b></span>\n        </div>\n        <div class="progress-outer"><div class="progress-inner" style="width:{pct}%"></div></div>\n    </div>""", unsafe_allow_html=True)\n\n    st.divider()\n    filtro = st.radio("Filtrar:", ["Todos","Conciliado","Divergente","So no Banco","So no ERP"],\n        format_func=lambda x: {"Todos":"Todos","Conciliado":"✅ Conciliado",\n            "Divergente":"⚠️ Divergente","So no Banco":"🏦 Só no Banco",\n            "So no ERP":"🗄️ Só no ERP"}.get(x,x),\n        horizontal=True, label_visibility="collapsed")\n\n    if filtro == "Todos":\n        filtrado = df\n    elif filtro == "So no Banco":\n        filtrado = df[df["status"].isin(["So no Banco","Nao Conciliado"])]\n    else:\n        filtrado = df[df["status"] == filtro]\n\n    linhas = ""\n    for _, row in filtrado.iterrows():\n        linhas += f"""<tr>\n            <td>{fmt_data(row.get("banco_data"))}</td>\n            <td>{fmt_valor(row.get("banco_valor"))}</td>\n            <td>{_badge_dc(row.get("banco_dc",""))}</td>\n            <td title="{row.get("banco_descricao") or ""}">{str(row.get("banco_descricao") or "—")[:30]}</td>\n            <td>{row.get("banco_documento") or "—"}</td>\n            <td>{fmt_data(row.get("erp_data"))}</td>\n            <td>{fmt_valor(row.get("erp_valor"))}</td>\n            <td>{_badge_dc(row.get("erp_dc",""))}</td>\n            <td title="{row.get("erp_descricao") or ""}">{str(row.get("erp_descricao") or "—")[:30]}</td>\n            <td>{row.get("erp_documento") or "—"}</td>\n            <td>{badge_html(str(row.get("status","—")))}</td>\n            <td>{conf_html(str(row.get("confianca","—")))}</td>\n            <td>{fmt_valor(row.get("diferenca_valor"))}</td>\n            <td>{str(int(row["diferenca_dias"]))+"d" if pd.notna(row.get("diferenca_dias")) else "—"}</td>\n        </tr>"""\n\n    st.markdown(f"""\n    <div style="overflow-x:auto;border-radius:10px;border:1px solid #e8e8e8;max-height:420px;overflow-y:auto">\n    <table class="result-table"><thead><tr>\n        <th>Data Banco</th><th>Valor Banco</th><th>D/C</th><th>Descr. Banco</th><th>Doc. Banco</th>\n        <th>Data ERP</th><th>Valor ERP</th><th>D/C</th><th>Descr. ERP</th><th>Doc. ERP</th>\n        <th>Status</th><th>Confiança</th><th>Dif. Valor</th><th>Dif. Dias</th>\n    </tr></thead><tbody>{linhas}</tbody></table></div>""", unsafe_allow_html=True)\n    st.caption(f"Exibindo {len(filtrado)} de {len(df)} lançamentos")\n\n    st.divider()\n    b1,_,b2 = st.columns([1,4,1])\n    with b1:\n        if st.button("← Voltar", use_container_width=True): S.step=2; st.rerun()\n    with b2:\n        if st.button("Exportar →", type="primary", use_container_width=True): S.step=4; st.rerun()\n\n# ── Etapa 4 — Exportar ────────────────────────────────────────────────────────\ndef etapa_exportar():\n    r  = S.resumo\n    df = S.df_result\n    st.markdown("### 📤 Exportar resultados")\n\n    col1,col2,col3,col4 = st.columns(4)\n    with col1:\n        st.markdown("#### 📊 Excel completo")\n        st.caption("Abas: Resumo, Conciliados, Divergentes, Não Conciliados, Só no ERP")\n        try:\n            st.download_button("⬇ Baixar Excel", data=exportar_excel(df,r),\n                file_name="conciliacao_bancaria.xlsx",\n                mime="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",\n                use_container_width=True, type="primary")\n        except Exception as e: st.error(f"Erro: {e}")\n\n    with col2:\n        st.markdown("#### 📋 CSV Input ERP")\n        st.caption("Lançamentos conciliados para reimportação")\n        try:\n            st.download_button("⬇ Baixar CSV", data=exportar_csv_erp(df),\n                file_name="conciliados_input_erp.csv", mime="text/csv",\n                use_container_width=True)\n        except Exception as e: st.error(f"Erro: {e}")\n\n    with col3:\n        st.markdown("#### 📈 CSV Divergências")\n        st.caption("Divergentes e não conciliados para revisão")\n        try:\n            div = df[df["status"].isin(["Divergente","So no Banco","So no ERP"])].copy()\n            st.download_button("⬇ Baixar Divergências",\n                data=div.to_csv(index=False,sep=";",encoding="utf-8-sig").encode("utf-8-sig"),\n                file_name="divergencias.csv", mime="text/csv", use_container_width=True)\n        except Exception as e: st.error(f"Erro: {e}")\n\n    with col4:\n        st.markdown("#### 📄 Relatório PDF")\n        st.caption("Relatório executivo completo")\n        try:\n            st.download_button("⬇ Baixar PDF", data=exportar_pdf(S.resultado_completo),\n                file_name="relatorio_conciliacao.pdf", mime="application/pdf",\n                use_container_width=True, type="primary")\n        except Exception as e: st.error(f"Erro: {e}")\n\n    st.divider()\n    st.markdown("#### 💰 Resumo Financeiro")\n    fc1,fc2,fc3 = st.columns(3)\n    with fc1: st.metric("Valor Conciliado",     fmt_valor(r.get("valor_conciliado",0)))\n    with fc2: st.metric("Valor Divergente",     fmt_valor(r.get("valor_divergente",0)))\n    with fc3: st.metric("Valor Não Conciliado", fmt_valor(r.get("valor_so_banco", r.get("valor_nao_conciliado",0))))\n\n    st.divider()\n    if st.button("← Nova conciliação"):\n        for k in ["raw_banco","raw_erp","df_result","resumo","resultado_completo"]:\n            S[k] = None\n        S.map_banco = {}; S.map_erp = {}; S.step = 0; st.rerun()\n\n# ── Roteador ──────────────────────────────────────────────────────────────────\nheader()\nrender_steps()\nif   S.step == 0: etapa_importar()\nelif S.step == 1: etapa_mapear()\nelif S.step == 2: etapa_criterios()\nelif S.step == 3: etapa_resultado()\nelif S.step == 4: etapa_exportar()\n'

CONCILIADOR = 'import re\nimport unicodedata\nimport pandas as pd\nimport numpy as np\nfrom datetime import datetime\nfrom difflib import SequenceMatcher\nfrom itertools import combinations\n\n\n# ══════════════════════════════════════════════════════════════════════════════\n# CONFIGURAÇÃO DE CAMPOS\n# ══════════════════════════════════════════════════════════════════════════════\n\nFIELD_HINTS = {\n    "data":      ["data", "dtmovimento", "datamov", "dtlancamento",\n                  "dtpagamento", "datapagamento", "competencia", "emissao", "baixa"],\n    "valor":     ["valor", "vl", "value", "montante", "amount", "total",\n                  "price", "preco", "pgto", "pago"],\n    "debito":    ["debito", "deb", "saida", "debit", "db"],\n    "credito":   ["credito", "cred", "entrada", "credit", "cr"],\n    "descricao": ["descricao", "descrição", "hist", "memo", "narr", "obs", "observ",\n                  "lancamento", "lançamento", "fornecedor", "cliente",\n                  "beneficiario", "name", "nome"],\n    "documento": ["documento", "doc", "nf", "nota", "numero", "número", "ref",\n                  "referencia", "cheque", "boleto", "nsu", "codigo", "dcto"],\n    "tipo":      ["tipo", "natureza", "d/c", "debcred", "modalidade", "operacao"],\n}\n\nFORMATOS_DATA = [\n    "%Y-%m-%d", "%d/%m/%Y", "%d/%m/%y", "%m/%d/%Y",\n    "%d-%m-%Y", "%d-%m-%y", "%Y/%m/%d",\n    "%d.%m.%Y", "%d.%m.%y", "%Y%m%d",\n]\n\n\n# ══════════════════════════════════════════════════════════════════════════════\n# PARSERS DE DATA E VALOR\n# ══════════════════════════════════════════════════════════════════════════════\n\ndef _parse_data(valor):\n    if valor is None:\n        return pd.NaT\n    if isinstance(valor, float) and np.isnan(valor):\n        return pd.NaT\n    if isinstance(valor, pd.Timestamp):\n        return valor.normalize()\n    if isinstance(valor, datetime):\n        return pd.Timestamp(valor).normalize()\n    s = str(valor).strip().split(" ")[0].split("T")[0]\n    if not s or s.lower() in ("nat", "nan", "none", ""):\n        return pd.NaT\n    for fmt in FORMATOS_DATA:\n        try:\n            return pd.Timestamp(datetime.strptime(s, fmt))\n        except ValueError:\n            continue\n    return pd.to_datetime(s, dayfirst=True, errors="coerce")\n\n\ndef _parse_valor(valor) -> float:\n    if valor is None:\n        return np.nan\n    if isinstance(valor, (int, float)):\n        return float(valor) if not (isinstance(valor, float) and np.isnan(valor)) else np.nan\n    s = str(valor).strip()\n    if not s or s.lower() in ("nan", "none", ""):\n        return np.nan\n    negativo = s.startswith("(") and s.endswith(")")\n    if negativo:\n        s = s[1:-1]\n    s = re.sub(r"[R$€£\\s\\"\']", "", s)\n    sinal = -1 if (s.startswith("-") or negativo) else 1\n    s = s.lstrip("-+")\n    if not s:\n        return np.nan\n    np_ = s.count(".")\n    nv  = s.count(",")\n    if np_ == 0 and nv == 0:\n        try:\n            return sinal * float(s)\n        except ValueError:\n            return np.nan\n    if np_ == 0 and nv == 1:\n        partes = s.split(",")\n        if len(partes[1]) == 3 and len(partes[0]) <= 3 and int(partes[1]) >= 100:\n            return sinal * float(s.replace(",", ""))\n        return sinal * float(s.replace(",", "."))\n    if np_ == 1 and nv == 0:\n        return sinal * float(s)\n    if np_ > 1 and nv == 0:\n        return sinal * float(s.replace(".", ""))\n    if nv > 1 and np_ == 0:\n        return sinal * float(s.replace(",", ""))\n    if nv >= 1 and np_ >= 1:\n        if s.rindex(".") < s.index(","):\n            return sinal * float(s.replace(".", "").replace(",", "."))\n        else:\n            return sinal * float(s.replace(",", ""))\n    try:\n        return sinal * float(s.replace(",", "."))\n    except ValueError:\n        return np.nan\n\n\n# ══════════════════════════════════════════════════════════════════════════════\n# NORMALIZAÇÃO DE TEXTO\n# ══════════════════════════════════════════════════════════════════════════════\n\ndef _normalizar_texto(texto) -> str:\n    if not texto or str(texto).lower() in ("nan", "none", ""):\n        return ""\n    s = str(texto)\n    s = unicodedata.normalize("NFD", s)\n    s = "".join(c for c in s if unicodedata.category(c) != "Mn")\n    s = s.lower()\n    s = re.sub(r"[^a-z0-9\\s]", " ", s)\n    s = re.sub(r"\\s+", " ", s).strip()\n    return s\n\n\ndef _similaridade(a, b) -> float:\n    na, nb = _normalizar_texto(a), _normalizar_texto(b)\n    if not na or not nb:\n        return 0.0\n    return SequenceMatcher(None, na, nb).ratio()\n\n\n# ══════════════════════════════════════════════════════════════════════════════\n# DETECÇÃO DE COLUNAS E CARREGAMENTO\n# ══════════════════════════════════════════════════════════════════════════════\n\ndef detect_columns(df: pd.DataFrame) -> dict:\n    """Detecta automaticamente as colunas. Retorna mapping com chaves:\n    data, valor, debito, credito, descricao, documento, tipo"""\n    cols_lower = {c: c.lower().replace(" ", "").replace("_", "") for c in df.columns}\n    mapping = {f: None for f in FIELD_HINTS}\n    for field, hints in FIELD_HINTS.items():\n        for col, col_clean in cols_lower.items():\n            if any(h in col_clean for h in hints):\n                mapping[field] = col\n                break\n    if not mapping["data"]:\n        for col in df.columns:\n            if pd.api.types.is_datetime64_any_dtype(df[col]):\n                mapping["data"] = col\n                break\n    if not mapping["valor"] and not mapping["debito"] and not mapping["credito"]:\n        for col in df.columns:\n            if pd.api.types.is_numeric_dtype(df[col]):\n                mapping["valor"] = col\n                break\n    return mapping\n\n\ndef load_sheet(raw: pd.DataFrame, mapping: dict) -> pd.DataFrame:\n    """Carrega planilha já lida (raw DataFrame) aplicando o mapping de colunas.\n    Suporta coluna única de valor OU par débito/crédito separados."""\n    df = pd.DataFrame()\n\n    # Data\n    col_data = mapping.get("data")\n    df["data"] = raw[col_data].apply(_parse_data) if (col_data and col_data in raw.columns) else pd.NaT\n\n    # Valor: prioriza coluna única; se não houver, combina débito e crédito\n    col_valor   = mapping.get("valor")\n    col_debito  = mapping.get("debito")\n    col_credito = mapping.get("credito")\n\n    if col_valor and col_valor in raw.columns:\n        serie = raw[col_valor].apply(_parse_valor)\n        # Detecta padrão Itaú: coluna única onde débito vem negativo e crédito positivo\n        validos = serie.dropna()\n        pct_neg = (validos < 0).sum() / len(validos) if len(validos) > 0 else 0\n        if pct_neg >= 0.05:\n            # Coluna mista D/C: separa e usa valor absoluto para conciliação\n            df["valor_credito"] = serie.where(serie > 0, np.nan)\n            df["valor_debito"]  = serie.where(serie < 0, np.nan).abs()\n            df["valor"]         = serie.abs()\n        else:\n            df["valor"]         = serie\n            df["valor_credito"] = np.nan\n            df["valor_debito"]  = np.nan\n    elif col_debito or col_credito:\n        serie_deb  = raw[col_debito].apply(_parse_valor)  if (col_debito  and col_debito  in raw.columns) else pd.Series(np.nan, index=raw.index)\n        serie_cred = raw[col_credito].apply(_parse_valor) if (col_credito and col_credito in raw.columns) else pd.Series(np.nan, index=raw.index)\n        serie_deb  = serie_deb.abs()\n        serie_cred = serie_cred.abs()\n        df["valor_debito"]  = serie_deb\n        df["valor_credito"] = serie_cred\n        df["valor"] = serie_cred.fillna(serie_deb)\n        df["valor"] = df["valor"].replace(0, np.nan)\n    else:\n        df["valor"]         = np.nan\n        df["valor_credito"] = np.nan\n        df["valor_debito"]  = np.nan\n\n    # Demais campos\n    for field in ("descricao", "documento", "tipo"):\n        col = mapping.get(field)\n        df[field] = raw[col] if (col and col in raw.columns) else np.nan\n\n    # Detecta tipo D/C\n    if "valor_debito" in df.columns and "valor_credito" in df.columns:\n        def _tipo_dc(row):\n            tem_cred = pd.notna(row.get("valor_credito")) and row.get("valor_credito", 0) > 0\n            tem_deb  = pd.notna(row.get("valor_debito"))  and row.get("valor_debito", 0)  > 0\n            if tem_cred and not tem_deb: return "C"\n            if tem_deb  and not tem_cred: return "D"\n            if tem_cred and tem_deb: return "C/D"\n            return ""\n        df["tipo_dc"] = df.apply(_tipo_dc, axis=1)\n    else:\n        df["tipo_dc"] = ""\n\n    df["_idx"] = range(len(df))\n\n    # ── Remove linhas completamente vazias (sem valor E sem data) ──\n    tem_valor = df["valor"].notna() & (df["valor"] != 0)\n    tem_data  = df["data"].notna()\n    df = df[tem_valor | tem_data].copy()\n    df = df.reset_index(drop=True)\n    df["_idx"] = range(len(df))\n\n    return df\n\n\n# ══════════════════════════════════════════════════════════════════════════════\n# SCORE DE CONFIABILIDADE\n# ══════════════════════════════════════════════════════════════════════════════\n\ndef _calcular_score(b, e, tol_valor, tol_dias, usar_doc, usar_desc, min_sim) -> dict:\n    resultado = {\n        "score": 0,\n        "ok_valor": False, "ok_data": False, "ok_doc": False, "ok_desc": False,\n        "dif_valor": None, "dif_dias": None, "sim_desc": 0.0,\n        "motivos": [], "dc_incompativel": False,\n    }\n\n    # ── Verifica compatibilidade D/C ──\n    # Se ambos os lados têm D/C identificado e são opostos (um D, outro C),\n    # não é a mesma natureza de lançamento — desqualifica o match.\n    dc_b = (b.get("tipo_dc") or "").strip()\n    dc_e = (e.get("tipo_dc") or "").strip()\n    if dc_b in ("D", "C") and dc_e in ("D", "C") and dc_b != dc_e:\n        resultado["dc_incompativel"] = True\n        resultado["motivos"].append(f"⚠ D/C incompatível (Banco={dc_b} / ERP={dc_e})")\n        return resultado  # score fica 0 — não concilia\n\n    if pd.notna(b.get("valor")) and pd.notna(e.get("valor")):\n        dif = abs(float(b["valor"]) - float(e["valor"]))\n        resultado["dif_valor"] = round(dif, 2)\n        if dif <= 0.001:\n            resultado["score"] += 40\n            resultado["ok_valor"] = True\n            resultado["motivos"].append("Valor exato")\n        elif dif <= tol_valor:\n            resultado["score"] += 25\n            resultado["ok_valor"] = True\n            resultado["motivos"].append(f"Valor (dif R$ {dif:.2f})")\n\n    if pd.notna(b.get("data")) and pd.notna(e.get("data")):\n        try:\n            dif_d = abs((pd.Timestamp(b["data"]) - pd.Timestamp(e["data"])).days)\n            resultado["dif_dias"] = dif_d\n            if dif_d == 0:\n                resultado["score"] += 30\n                resultado["ok_data"] = True\n                resultado["motivos"].append("Data exata")\n            elif dif_d <= tol_dias:\n                resultado["score"] += 20\n                resultado["ok_data"] = True\n                resultado["motivos"].append(f"Data ({dif_d}d diferenca)")\n        except Exception:\n            pass\n\n    if usar_doc:\n        bd = str(b.get("documento", "")).strip()\n        ed = str(e.get("documento", "")).strip()\n        if bd and ed and bd not in ("nan", "None", "") and ed not in ("nan", "None", "") and bd == ed:\n            resultado["score"] += 20\n            resultado["ok_doc"] = True\n            resultado["motivos"].append("Documento igual")\n\n    if usar_desc:\n        sim = _similaridade(b.get("descricao"), e.get("descricao"))\n        resultado["sim_desc"] = round(sim * 100, 1)\n        if sim >= min_sim:\n            resultado["score"] += 10\n            resultado["ok_desc"] = True\n            resultado["motivos"].append(f"Descricao {resultado[\'sim_desc\']}%")\n\n    return resultado\n\n\ndef _nivel_confianca(score: int):\n    if score >= 90:\n        return "Alta",       "ok"\n    if score >= 70:\n        return "Média",      "warn"\n    if score >= 50:\n        return "Baixa",      "info"\n    return "Muito Baixa",    "err"\n\n\ndef _tipo_match(sc: dict) -> str:\n    if sc["ok_valor"] and sc["ok_data"] and sc["ok_doc"]:\n        return "Match Exato"\n    if sc["ok_valor"] and sc["ok_data"]:\n        return "Match por Similaridade"\n    if sc["ok_valor"]:\n        return "Match por Tolerancia"\n    return "Correspondencia Parcial"\n\n\n# ══════════════════════════════════════════════════════════════════════════════\n# DETECÇÃO DE DUPLICIDADES\n# ══════════════════════════════════════════════════════════════════════════════\n\ndef detectar_duplicidades(df: pd.DataFrame, origem: str) -> pd.DataFrame:\n    df = df.copy()\n    df["_dup_key"] = df["valor"].astype(str) + "_" + df["data"].astype(str)\n    contagem = df["_dup_key"].value_counts()\n    duplicados = contagem[contagem > 1].index\n    df_dup = df[df["_dup_key"].isin(duplicados)].copy()\n    df_dup["origem"] = origem\n    df_dup = df_dup.drop(columns=["_dup_key", "_idx"], errors="ignore")\n    return df_dup\n\n\n# ══════════════════════════════════════════════════════════════════════════════\n# AGRUPAMENTO E DESMEMBRAMENTO\n# ══════════════════════════════════════════════════════════════════════════════\n\ndef _buscar_combinacoes(valor_alvo: float, df_pool: pd.DataFrame,\n                        tol: float = 0.01, max_itens: int = 5) -> list:\n    candidatos = []\n    pool = df_pool[pd.notna(df_pool["valor"])].copy()\n    pool = pool[pool["valor"] <= valor_alvo + tol]\n    if len(pool) == 0 or len(pool) > 50:\n        return candidatos\n    indices = list(pool.index)\n    for n in range(2, min(max_itens + 1, len(indices) + 1)):\n        for combo in combinations(indices, n):\n            soma = pool.loc[list(combo), "valor"].sum()\n            if abs(soma - valor_alvo) <= tol:\n                candidatos.append(pool.loc[list(combo)])\n                if len(candidatos) >= 3:\n                    return candidatos\n    return candidatos\n\n\ndef conciliar_agrupamentos(df_nao_conc_banco, df_nao_conc_erp,\n                            tol_valor=0.01, tol_dias=5) -> list:\n    resultados = []\n    usado_erp   = set()\n    usado_banco = set()\n\n    for bi, b in df_nao_conc_banco.iterrows():\n        if bi in usado_banco or pd.isna(b.get("valor")):\n            continue\n        pool_erp = df_nao_conc_erp[~df_nao_conc_erp.index.isin(usado_erp)]\n        if pd.notna(b.get("data")):\n            pool_erp = pool_erp[\n                pool_erp["data"].apply(\n                    lambda d: abs((pd.Timestamp(d) - pd.Timestamp(b["data"])).days) <= tol_dias\n                    if pd.notna(d) else True\n                )\n            ]\n        combos = _buscar_combinacoes(float(b["valor"]), pool_erp, tol_valor)\n        for combo in combos:\n            resultados.append({\n                "tipo":        "Agrupamento",\n                "descricao":   "1 lancamento bancario = soma de multiplos no ERP",\n                "banco_idx":   [bi],\n                "erp_idx":     list(combo.index),\n                "banco_valor": b["valor"],\n                "erp_valores": list(combo["valor"]),\n                "soma_erp":    combo["valor"].sum(),\n                "banco_data":  b.get("data"),\n                "banco_desc":  b.get("descricao"),\n                "score":       85,\n                "confianca":   "Alta",\n            })\n            usado_banco.add(bi)\n            usado_erp.update(combo.index)\n            break\n\n    for ei, e in df_nao_conc_erp.iterrows():\n        if ei in usado_erp or pd.isna(e.get("valor")):\n            continue\n        pool_banco = df_nao_conc_banco[~df_nao_conc_banco.index.isin(usado_banco)]\n        if pd.notna(e.get("data")):\n            pool_banco = pool_banco[\n                pool_banco["data"].apply(\n                    lambda d: abs((pd.Timestamp(d) - pd.Timestamp(e["data"])).days) <= tol_dias\n                    if pd.notna(d) else True\n                )\n            ]\n        combos = _buscar_combinacoes(float(e["valor"]), pool_banco, tol_valor)\n        for combo in combos:\n            resultados.append({\n                "tipo":          "Desmembramento",\n                "descricao":     "1 lancamento ERP liquidado em multiplos no banco",\n                "banco_idx":     list(combo.index),\n                "erp_idx":       [ei],\n                "banco_valores": list(combo["valor"]),\n                "soma_banco":    combo["valor"].sum(),\n                "erp_valor":     e["valor"],\n                "erp_data":      e.get("data"),\n                "erp_desc":      e.get("descricao"),\n                "score":         80,\n                "confianca":     "Alta",\n            })\n            usado_erp.add(ei)\n            usado_banco.update(combo.index)\n            break\n\n    return resultados\n\n\n# ══════════════════════════════════════════════════════════════════════════════\n# ENGINE PRINCIPAL\n# ══════════════════════════════════════════════════════════════════════════════\n\ndef conciliar(\n    df_banco,\n    df_erp,\n    tol_valor=0.01,\n    tol_dias=2,\n    usar_documento=True,\n    usar_descricao=False,\n    min_similaridade=0.70,\n) -> dict:\n    banco = df_banco.copy().reset_index(drop=True)\n    erp   = df_erp.copy().reset_index(drop=True)\n    usado_erp = set()\n    rows = []\n\n    for bi, b in banco.iterrows():\n        melhor_sc    = None\n        melhor_score = 0\n        melhor_ei    = None\n        melhor_e     = None\n\n        for ei, e in erp.iterrows():\n            if ei in usado_erp:\n                continue\n            sc = _calcular_score(b, e, tol_valor, tol_dias,\n                                 usar_documento, usar_descricao, min_similaridade)\n            if sc["score"] > melhor_score and sc["score"] >= 40:\n                melhor_score = sc["score"]\n                melhor_sc    = sc\n                melhor_ei    = ei\n                melhor_e     = e\n\n        if melhor_e is not None:\n            usado_erp.add(melhor_ei)\n            sc       = melhor_sc\n            nivel, _ = _nivel_confianca(sc["score"])\n            tipo_m   = _tipo_match(sc)\n            status   = "Conciliado" if sc["score"] >= 70 else "Divergente"\n\n            motivo_div = []\n            if sc["dif_valor"] is not None and sc["dif_valor"] > 0.001:\n                motivo_div.append(f"Valor dif R$ {sc[\'dif_valor\']:.2f}")\n            if sc["dif_dias"] is not None and sc["dif_dias"] > 0:\n                motivo_div.append(f"Data {sc[\'dif_dias\']}d")\n            if usar_descricao and not sc["ok_desc"]:\n                motivo_div.append("Descricao divergente")\n\n            rows.append({\n                "banco_data":      b.get("data"),\n                "banco_valor":     b.get("valor"),\n                "banco_debito":    b.get("valor_debito"),\n                "banco_credito":   b.get("valor_credito"),\n                "banco_descricao": b.get("descricao"),\n                "banco_documento": b.get("documento"),\n                "erp_data":        melhor_e.get("data"),\n                "erp_valor":       melhor_e.get("valor"),\n                "erp_debito":      melhor_e.get("valor_debito"),\n                "erp_credito":     melhor_e.get("valor_credito"),\n                "erp_descricao":   melhor_e.get("descricao"),\n                "erp_documento":   melhor_e.get("documento"),\n                "status":          status,\n                "tipo_match":      tipo_m,\n                "score":           sc["score"],\n                "confianca":       nivel,\n                "motivos":         " | ".join(sc["motivos"]),\n                "divergencias":    " | ".join(motivo_div) if motivo_div else "—",\n                "diferenca_valor": sc["dif_valor"],\n                "diferenca_dias":  sc["dif_dias"],\n                "sim_descricao":   sc["sim_desc"],\n                "_banco_idx":      bi,\n                "_erp_idx":        melhor_ei,\n            })\n        else:\n            rows.append({\n                "banco_data":      b.get("data"),\n                "banco_valor":     b.get("valor"),\n                "banco_debito":    b.get("valor_debito"),\n                "banco_credito":   b.get("valor_credito"),\n                "banco_descricao": b.get("descricao"),\n                "banco_documento": b.get("documento"),\n                "erp_data":        None, "erp_valor":     None,\n                "erp_debito":      None, "erp_credito":   None,\n                "erp_descricao":   None, "erp_documento": None,\n                "status":          "Nao Conciliado",\n                "tipo_match":      "—",\n                "score":           0,   "confianca": "—",\n                "motivos":         "—", "divergencias": "Sem par no ERP",\n                "diferenca_valor": None, "diferenca_dias": None,\n                "sim_descricao":   0.0,\n                "_banco_idx":      bi,  "_erp_idx": None,\n            })\n\n    for ei, e in erp.iterrows():\n        if ei not in usado_erp:\n            rows.append({\n                "banco_data":      None, "banco_valor":     None,\n                "banco_debito":    None, "banco_credito":   None,\n                "banco_descricao": None, "banco_documento": None,\n                "erp_data":        e.get("data"),\n                "erp_valor":       e.get("valor"),\n                "erp_debito":      e.get("valor_debito"),\n                "erp_credito":     e.get("valor_credito"),\n                "erp_descricao":   e.get("descricao"),\n                "erp_documento":   e.get("documento"),\n                "status":          "So no ERP",\n                "tipo_match":      "—",\n                "score":           0,   "confianca": "—",\n                "motivos":         "—", "divergencias": "Sem par no banco",\n                "diferenca_valor": None, "diferenca_dias": None,\n                "sim_descricao":   0.0,\n                "_banco_idx":      None, "_erp_idx": ei,\n            })\n\n    df_resultado = pd.DataFrame(rows)\n\n    nc_banco_idx = df_resultado[df_resultado["status"] == "Nao Conciliado"]["_banco_idx"].dropna().astype(int).tolist()\n    nc_erp_idx   = df_resultado[df_resultado["status"] == "So no ERP"]["_erp_idx"].dropna().astype(int).tolist()\n    df_nc_banco  = banco.loc[banco.index.isin(nc_banco_idx)].copy()\n    df_nc_erp    = erp.loc[erp.index.isin(nc_erp_idx)].copy()\n\n    agrupamentos = []\n    if len(df_nc_banco) > 0 and len(df_nc_erp) > 0:\n        agrupamentos = conciliar_agrupamentos(df_nc_banco, df_nc_erp, tol_valor)\n\n    sugestoes = []\n    for bi, b in banco.loc[banco.index.isin(nc_banco_idx)].iterrows():\n        for ei, e in erp.iterrows():\n            if ei in usado_erp:\n                continue\n            sc = _calcular_score(b, e, tol_valor * 5, tol_dias * 3, usar_documento, True, 0.4)\n            if 20 <= sc["score"] < 40:\n                sugestoes.append({\n                    "banco_data":      b.get("data"),\n                    "banco_valor":     b.get("valor"),\n                    "banco_descricao": b.get("descricao"),\n                    "erp_data":        e.get("data"),\n                    "erp_valor":       e.get("valor"),\n                    "erp_descricao":   e.get("descricao"),\n                    "score":           sc["score"],\n                    "motivos":         " | ".join(sc["motivos"]) or "Similaridade parcial",\n                })\n\n    dup_banco = detectar_duplicidades(banco, "Banco")\n    dup_erp   = detectar_duplicidades(erp,   "ERP")\n\n    return {\n        "resultado":          df_resultado,\n        "agrupamentos":       agrupamentos,\n        "sugestoes":          sugestoes[:20],\n        "duplicidades_banco": dup_banco,\n        "duplicidades_erp":   dup_erp,\n        "resumo":             _calcular_resumo(df_resultado, agrupamentos, dup_banco, dup_erp),\n    }\n\n\n# ══════════════════════════════════════════════════════════════════════════════\n# RESUMO EXECUTIVO\n# ══════════════════════════════════════════════════════════════════════════════\n\ndef _calcular_resumo(df, agrupamentos, dup_banco, dup_erp) -> dict:\n    total_banco  = len(df[df["banco_valor"].notna()])\n    total_erp    = len(df[df["erp_valor"].notna()])\n    conciliados  = len(df[df["status"] == "Conciliado"])\n    divergentes  = len(df[df["status"] == "Divergente"])\n    nao_conc     = len(df[df["status"] == "Nao Conciliado"])\n    so_erp       = len(df[df["status"] == "So no ERP"])\n    n_agrup      = len([a for a in agrupamentos if a["tipo"] == "Agrupamento"])\n    n_desmemb    = len([a for a in agrupamentos if a["tipo"] == "Desmembramento"])\n    taxa         = round(conciliados / total_banco * 100, 1) if total_banco else 0.0\n    conc_df      = df[df["status"] == "Conciliado"]\n    score_medio  = round(conc_df["score"].mean(), 1) if len(conc_df) > 0 else 0.0\n\n    return {\n        "total_banco":          total_banco,\n        "total_erp":            total_erp,\n        "conciliados":          conciliados,\n        "divergentes":          divergentes,\n        "nao_conciliados":      nao_conc,\n        "so_erp":               so_erp,\n        "agrupamentos":         n_agrup,\n        "desmembramentos":      n_desmemb,\n        "taxa_pct":             taxa,\n        "score_medio":          score_medio,\n        "valor_total_banco":    df["banco_valor"].sum(),\n        "valor_conciliado":     df[df["status"] == "Conciliado"]["banco_valor"].sum(),\n        "valor_divergente":     df[df["status"] == "Divergente"]["banco_valor"].sum(),\n        "valor_nao_conciliado": df[df["status"] == "Nao Conciliado"]["banco_valor"].sum(),\n        "valor_so_erp":         df[df["status"] == "So no ERP"]["erp_valor"].sum(),\n        "duplicidades_banco":   len(dup_banco),\n        "duplicidades_erp":     len(dup_erp),\n    }\n\n\ndef resumo(resultado):\n    if isinstance(resultado, dict):\n        return resultado["resumo"]\n    return _calcular_resumo(resultado, [], pd.DataFrame(), pd.DataFrame())\n'

EXPORTAR = 'import io\nimport pandas as pd\nfrom openpyxl import Workbook\nfrom openpyxl.styles import Font, PatternFill, Alignment, PatternFill, Border, Side\nfrom openpyxl.utils import get_column_letter\n\n\n# ─── Paleta ───────────────────────────────────────────────────────────────────\nCOR_VERDE_ESCURO  = "085041"\nCOR_VERDE_CLARO   = "E1F5EE"\nCOR_AMARELO_CLARO = "FAEEDA"\nCOR_AMARELO_ESC   = "633806"\nCOR_VERMELHO_CLARO= "FCEBEB"\nCOR_VERMELHO_ESC  = "791F1F"\nCOR_AZUL_CLARO    = "E6F1FB"\nCOR_AZUL_ESC      = "0C447C"\nCOR_CINZA         = "F1EFE8"\nCOR_CINZA_ESC     = "444441"\nBRANCO            = "FFFFFF"\n\nSTATUS_CORES = {\n    "Conciliado":     (COR_VERDE_CLARO,   COR_VERDE_ESCURO),\n    "Divergente":     (COR_AMARELO_CLARO, COR_AMARELO_ESC),\n    "Nao Conciliado": (COR_VERMELHO_CLARO,COR_VERMELHO_ESC),\n    "So no ERP":      (COR_AZUL_CLARO,    COR_AZUL_ESC),\n}\n\n\ndef _fill(hex_color: str) -> PatternFill:\n    return PatternFill("solid", start_color=hex_color, fgColor=hex_color)\n\n\ndef _thin_border():\n    s = Side(style="thin", color="CCCCCC")\n    return Border(left=s, right=s, top=s, bottom=s)\n\n\ndef _header_style(ws, row, cols, bg=COR_VERDE_ESCURO, fg=BRANCO):\n    for c in range(1, cols + 1):\n        cell = ws.cell(row=row, column=c)\n        cell.font = Font(bold=True, color=fg, size=10)\n        cell.fill = _fill(bg)\n        cell.alignment = Alignment(horizontal="center", vertical="center", wrap_text=True)\n        cell.border = _thin_border()\n\n\ndef _auto_width(ws, min_w=10, max_w=40):\n    for col in ws.columns:\n        length = max(\n            len(str(cell.value)) if cell.value else 0 for cell in col\n        )\n        ws.column_dimensions[get_column_letter(col[0].column)].width = min(max(length + 2, min_w), max_w)\n\n\ndef _fmt_valor(v):\n    if v is None or pd.isna(v):\n        return "—"\n    return f"R$ {v:,.2f}".replace(",", "X").replace(".", ",").replace("X", ".")\n\n\ndef _fmt_data(d):\n    if d is None or pd.isna(d):\n        return "—"\n    try:\n        return pd.Timestamp(d).strftime("%d/%m/%Y")\n    except Exception:\n        return str(d)\n\n\n# ─── Excel completo ───────────────────────────────────────────────────────────\n\ndef exportar_excel(df_resultado: pd.DataFrame, resumo_dict: dict) -> bytes:\n    wb = Workbook()\n    wb.remove(wb.active)\n\n    _aba_resumo(wb, resumo_dict)\n    _aba_status(wb, df_resultado, "Conciliados",     ["Conciliado"])\n    _aba_status(wb, df_resultado, "Divergentes",     ["Divergente"])\n    _aba_status(wb, df_resultado, "Nao Conciliados", ["Nao Conciliado"])\n    _aba_status(wb, df_resultado, "So no Banco",     ["So no Banco"])\n    _aba_status(wb, df_resultado, "So no ERP",       ["So no ERP"])\n    _aba_completa(wb, df_resultado)\n\n    buf = io.BytesIO()\n    wb.save(buf)\n    return buf.getvalue()\n\n\ndef _aba_resumo(wb, res: dict):\n    ws = wb.create_sheet("Resumo")\n    ws.sheet_view.showGridLines = False\n\n    # Título\n    ws.merge_cells("A1:D1")\n    ws["A1"] = "CONCILIAÇÃO BANCÁRIA — RESUMO EXECUTIVO"\n    ws["A1"].font = Font(bold=True, size=14, color=BRANCO)\n    ws["A1"].fill = _fill(COR_VERDE_ESCURO)\n    ws["A1"].alignment = Alignment(horizontal="center", vertical="center")\n    ws.row_dimensions[1].height = 32\n\n    # Métricas\n    metricas = [\n        ("Total lançamentos banco",    res["total_banco"],       COR_CINZA,          COR_CINZA_ESC),\n        ("Conciliados",                res["conciliados"],        COR_VERDE_CLARO,    COR_VERDE_ESCURO),\n        ("Divergentes",                res["divergentes"],        COR_AMARELO_CLARO,  COR_AMARELO_ESC),\n        ("Não conciliados",            res["nao_conciliados"],    COR_VERMELHO_CLARO, COR_VERMELHO_ESC),\n        ("So no ERP",                  res["so_erp"],             COR_AZUL_CLARO,     COR_AZUL_ESC),\n        ("Taxa de conciliação (%)",    f"{res[\'taxa_pct\']}%",     COR_VERDE_CLARO,    COR_VERDE_ESCURO),\n    ]\n\n    ws["A3"] = "Indicador"\n    ws["B3"] = "Valor"\n    _header_style(ws, 3, 2)\n\n    for i, (label, val, bg, fg) in enumerate(metricas, start=4):\n        ws.cell(row=i, column=1, value=label).fill = _fill(bg)\n        ws.cell(row=i, column=1).font = Font(color=fg, size=10)\n        ws.cell(row=i, column=1).border = _thin_border()\n        ws.cell(row=i, column=2, value=val).fill = _fill(bg)\n        ws.cell(row=i, column=2).font = Font(bold=True, color=fg, size=10)\n        ws.cell(row=i, column=2).alignment = Alignment(horizontal="center")\n        ws.cell(row=i, column=2).border = _thin_border()\n\n    # Valores financeiros\n    ws["A11"] = "Resumo Financeiro"\n    ws["A11"].font = Font(bold=True, size=11, color=BRANCO)\n    ws["A11"].fill = _fill(COR_VERDE_ESCURO)\n    ws.merge_cells("A11:B11")\n\n    fin = [\n        ("Valor conciliado",      _fmt_valor(res["valor_conciliado"])),\n        ("Valor divergente",      _fmt_valor(res["valor_divergente"])),\n        ("Valor não conciliado",  _fmt_valor(res["valor_nao_conciliado"])),\n    ]\n    for i, (label, val) in enumerate(fin, start=12):\n        ws.cell(row=i, column=1, value=label).border = _thin_border()\n        ws.cell(row=i, column=2, value=val).border = _thin_border()\n        ws.cell(row=i, column=2).alignment = Alignment(horizontal="right")\n\n    ws.column_dimensions["A"].width = 30\n    ws.column_dimensions["B"].width = 18\n\n\ndef _aba_status(wb, df, nome_aba, status_list):\n    filtrado = df[df["status"].isin(status_list)].copy()\n    ws = wb.create_sheet(nome_aba)\n    ws.sheet_view.showGridLines = False\n\n    cabecalhos = [\n        "Data Banco", "Valor Banco", "D/C Banco", "Descr. Banco", "Doc. Banco",\n        "Data ERP",   "Valor ERP",   "D/C ERP",   "Descr. ERP",   "Doc. ERP",\n        "Status", "Confiança", "Dif. Valor (R$)", "Dif. Dias"\n    ]\n\n    bg = STATUS_CORES.get(status_list[0], (COR_CINZA, COR_CINZA_ESC))[0]\n    fg = STATUS_CORES.get(status_list[0], (COR_CINZA, COR_CINZA_ESC))[1]\n\n    for c, h in enumerate(cabecalhos, 1):\n        cell = ws.cell(row=1, column=c, value=h)\n        cell.font = Font(bold=True, color=fg, size=10)\n        cell.fill = _fill(bg)\n        cell.alignment = Alignment(horizontal="center", vertical="center")\n        cell.border = _thin_border()\n    ws.row_dimensions[1].height = 22\n\n    for r, row in enumerate(filtrado.itertuples(), start=2):\n        # Status em português\n        status_label = {\n            "Conciliado":     "Conciliado",\n            "Divergente":     "Divergente",\n            "Nao Conciliado": "Não Conciliado",\n            "So no Banco":    "Só no Banco",\n            "So no ERP":      "Só no ERP",\n        }.get(row.status, row.status)\n        banco_dc = getattr(row, "banco_dc", "") or ""\n        erp_dc   = getattr(row, "erp_dc",   "") or ""\n        vals = [\n            _fmt_data(row.banco_data),  _fmt_valor(row.banco_valor),\n            banco_dc,\n            row.banco_descricao or "—", row.banco_documento or "—",\n            _fmt_data(row.erp_data),    _fmt_valor(row.erp_valor),\n            erp_dc,\n            row.erp_descricao or "—",   row.erp_documento or "—",\n            status_label, row.confianca,\n            _fmt_valor(row.diferenca_valor),\n            str(row.diferenca_dias) if row.diferenca_dias is not None else "—",\n        ]\n        for c, v in enumerate(vals, 1):\n            cell = ws.cell(row=r, column=c, value=v)\n            cell.border = _thin_border()\n            cell.font = Font(size=9)\n            if r % 2 == 0:\n                cell.fill = _fill("F7F7F5")\n\n    _auto_width(ws)\n\n\ndef _aba_completa(wb, df):\n    _aba_status(wb, df, "Todos os Lançamentos", df["status"].unique().tolist())\n\n\n# ─── CSV input ERP ────────────────────────────────────────────────────────────\n\ndef exportar_csv_erp(df_resultado: pd.DataFrame) -> bytes:\n    conc = df_resultado[df_resultado["status"] == "Conciliado"].copy()\n    conc = conc[["erp_data", "erp_valor", "erp_descricao", "erp_documento"]].copy()\n    conc.columns = ["Data", "Valor", "Descricao", "Documento"]\n    conc["Data"] = conc["Data"].apply(_fmt_data)\n    conc["Valor"] = conc["Valor"].apply(\n        lambda v: f"{v:.2f}".replace(".", ",") if pd.notna(v) else ""\n    )\n    buf = io.StringIO()\n    conc.to_csv(buf, index=False, sep=";", encoding="utf-8-sig")\n    return buf.getvalue().encode("utf-8-sig")\n'

salvar("app.py", APP)
